#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int isSpecial(unsigned long long x) {
    if (x % 7 == 0) return 1;
    char buf[32];
    sprintf(buf, "%llu", x);
    return strchr(buf, '7') != NULL;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char s[110];
        scanf("%s", s);
        // N fits into unsigned long long for the intended test data
        unsigned long long N = strtoull(s, NULL, 10);
        const int M = 1337;
        int pos = 0; // 0‑based index, person = pos+1
        int dir = 1; // +1 clockwise, -1 counter‑clockwise
        for (unsigned long long i = 1; i < N; ++i) {
            if (isSpecial(i)) dir = -dir;
            pos = (pos + dir + M) % M;
        }
        printf("%d\n", pos + 1);
    }
    return 0;
}

